'use client'

import { useEffect, useMemo, useRef, useState } from 'react'
import { ChevronDown, Pencil, Search } from 'lucide-react'
import { supabaseBrowser } from '@/lib/supabase/browser'
import type { CalculatorItem } from '@/lib/supabase/types'
import { fetchCalculatorItems } from '@/lib/calculator-cache'
import { Calculator } from './calculator'
import { ScheduleCalculator, type ScheduleCountry } from './schedule-calculator'

type Mode = 'cost' | 'schedule'

const MODES: Array<{ value: Mode; label: string }> = [
  { value: 'cost', label: '비용' },
  { value: 'schedule', label: '일정' },
]

const SCHEDULE_COUNTRIES: Array<{ value: ScheduleCountry; label: string }> = [
  { value: 'japan', label: '일본' },
  { value: 'australia', label: '호주' },
  { value: 'nz', label: '뉴질랜드' },
]

export function CalculatorApp() {
  const [mode, setMode] = useState<Mode>('cost')
  const [items, setItems] = useState<CalculatorItem[] | null>(null)
  const [canEdit, setCanEdit] = useState(false)

  // Cost mode toolbar state (lifted)
  const [species, setSpecies] = useState<'dog' | 'cat'>('dog')
  const [country, setCountry] = useState<string>('일본')
  const [editMode, setEditMode] = useState(false)
  const [dropOpen, setDropOpen] = useState(false)
  const [search, setSearch] = useState('')
  const dropRef = useRef<HTMLDivElement>(null)

  // Schedule mode toolbar state
  const [scheduleCountry, setScheduleCountry] = useState<ScheduleCountry>('japan')

  useEffect(() => {
    let alive = true
    ;(async () => {
      const [rows, { data: userData }] = await Promise.all([
        fetchCalculatorItems(),
        supabaseBrowser.auth.getUser(),
      ])
      if (!alive) return
      setItems(rows)
      setCanEdit(!!userData?.user)
    })()
    return () => {
      alive = false
    }
  }, [])

  useEffect(() => {
    if (!dropOpen) return
    const onDown = (e: MouseEvent) => {
      if (dropRef.current && !dropRef.current.contains(e.target as Node)) {
        setDropOpen(false)
        setSearch('')
      }
    }
    document.addEventListener('mousedown', onDown)
    return () => document.removeEventListener('mousedown', onDown)
  }, [dropOpen])

  const countries = useMemo(() => {
    if (!items) return []
    const seen = new Map<string, number>()
    for (const it of items) {
      if (it.country.includes('(고양이)')) continue
      if (!seen.has(it.country)) seen.set(it.country, it.country_order)
    }
    return [...seen.entries()].sort((a, b) => a[1] - b[1]).map(([n]) => n)
  }, [items])

  const filteredCountries = countries.filter((c) => c.includes(search))

  return (
    <div className="h-full overflow-auto scrollbar-minimal px-lg py-10 2xl:px-xl 3xl:px-2xl 4xl:px-3xl">
      <div className="mx-auto max-w-2xl flex flex-col gap-md">
        {/* Tabs + toolbar — same row on desktop, stacked on mobile */}
        <div className="flex flex-col md:flex-row md:items-end md:justify-between gap-sm md:gap-md border-b border-border/60 shrink-0">
          <div className="flex gap-xs">
            {MODES.map((m) => (
              <button
                key={m.value}
                type="button"
                onClick={() => setMode(m.value)}
                className={`px-md py-2 text-base font-medium transition-colors border-b-2 -mb-px ${
                  mode === m.value
                    ? 'border-primary text-primary'
                    : 'border-transparent text-muted-foreground hover:text-foreground'
                }`}
              >
                {m.label}
              </button>
            ))}
          </div>

          <div className="pb-2 md:pb-0 md:mb-1 flex items-center gap-2 flex-wrap">
            {mode === 'cost' && (
              <>
                {canEdit && (
                  <button
                    type="button"
                    onClick={() => setEditMode((v) => !v)}
                    className={`inline-flex h-8 items-center gap-1.5 rounded-md border px-3 text-sm font-medium transition-colors ${
                      editMode
                        ? 'border-primary bg-primary/10 text-primary'
                        : 'border-border bg-card text-muted-foreground hover:bg-accent hover:text-foreground'
                    }`}
                  >
                    <Pencil size={14} />
                    {editMode ? '수정 완료' : '가격 수정'}
                  </button>
                )}

                {/* Species segment */}
                <div className="inline-flex rounded-md border border-border bg-card p-0.5">
                  {([
                    ['dog', '강아지'],
                    ['cat', '고양이'],
                  ] as const).map(([v, label]) => {
                    const active = species === v
                    return (
                      <button
                        key={v}
                        type="button"
                        onClick={() => setSpecies(v)}
                        className={`h-7 rounded px-3 text-sm font-medium transition-colors ${
                          active
                            ? 'bg-primary/10 text-primary'
                            : 'text-muted-foreground hover:text-foreground'
                        }`}
                      >
                        {label}
                      </button>
                    )
                  })}
                </div>

                {/* Country dropdown */}
                <div className="relative" ref={dropRef}>
                  <button
                    type="button"
                    onClick={() => setDropOpen((v) => !v)}
                    className={`inline-flex h-8 items-center gap-1.5 rounded-md border bg-card px-3 text-sm font-medium transition-colors ${
                      dropOpen
                        ? 'border-primary text-primary'
                        : country
                        ? 'border-border text-foreground hover:bg-accent'
                        : 'border-border text-muted-foreground hover:bg-accent hover:text-foreground'
                    }`}
                  >
                    <Search size={14} />
                    <span>{country || '목적지'}</span>
                    <ChevronDown
                      size={14}
                      className={`transition-transform ${dropOpen ? 'rotate-180' : ''}`}
                    />
                  </button>
                  {dropOpen && (
                    <div className="absolute right-0 top-[calc(100%+4px)] z-50 w-64 overflow-hidden rounded-md border border-border bg-popover shadow-lg">
                      <div className="border-b border-border p-2">
                        <div className="relative">
                          <Search
                            size={14}
                            className="absolute left-2.5 top-1/2 -translate-y-1/2 text-muted-foreground"
                          />
                          <input
                            autoFocus
                            value={search}
                            onChange={(e) => setSearch(e.target.value)}
                            placeholder="목적지 검색..."
                            className="h-9 w-full rounded-md border border-border bg-background py-2 pl-8 pr-2 text-sm outline-none focus:border-primary"
                          />
                        </div>
                      </div>
                      <div className="scrollbar-minimal max-h-60 overflow-y-auto">
                        {filteredCountries.length === 0 ? (
                          <div className="px-3 py-3 text-sm text-muted-foreground">검색 결과 없음</div>
                        ) : (
                          filteredCountries.map((c) => {
                            const sel = c === country
                            return (
                              <button
                                key={c}
                                type="button"
                                onClick={() => {
                                  setCountry(c)
                                  setDropOpen(false)
                                  setSearch('')
                                }}
                                className={`block w-full px-3 py-2 text-left text-[15px] transition-colors ${
                                  sel
                                    ? 'bg-accent text-foreground font-medium'
                                    : 'text-foreground hover:bg-accent'
                                }`}
                              >
                                {c}
                              </button>
                            )
                          })
                        )}
                      </div>
                    </div>
                  )}
                </div>
              </>
            )}

            {mode === 'schedule' && (
              <div className="inline-flex rounded-md border border-border bg-card p-0.5">
                {SCHEDULE_COUNTRIES.map((c) => {
                  const active = scheduleCountry === c.value
                  return (
                    <button
                      key={c.value}
                      type="button"
                      onClick={() => setScheduleCountry(c.value)}
                      className={`h-7 rounded px-3 text-sm font-medium transition-colors ${
                        active
                          ? 'bg-primary/10 text-primary'
                          : 'text-muted-foreground hover:text-foreground'
                      }`}
                    >
                      {c.label}
                    </button>
                  )
                })}
              </div>
            )}
          </div>
        </div>

        {/* Body */}
        {mode === 'cost' ? (
          items === null ? (
            <div className="text-sm text-muted-foreground">불러오는 중...</div>
          ) : (
            <Calculator
              items={items}
              setItems={setItems}
              species={species}
              country={country}
              editMode={editMode}
            />
          )
        ) : (
          <ScheduleCalculator country={scheduleCountry} />
        )}
      </div>
    </div>
  )
}
